import { useEffect, useState } from "react";

function App() {
  const [loading, setLoading] = useState(true);
  const [coins, setCoins] = useState([]);
  const [coinValue, setCoinValue] = useState("Select coin");
  const [dollar, setDollar] = useState("");
  useEffect(() => {
    fetch("https://api.coinpaprika.com/v1/tickers?limit=100")
      .then((response) => response.json())
      .then((json) => {
        setCoins(json);
        setLoading(false);
      });
  }, []);
  function onSelect(event) {
    setCoinValue(event.target.value);
  }
  function onChangeDollar(event) {
    setDollar(event.target.value);
  }
  return (
    <div>
      <h1>The Coins!{loading ? "" : `(${coins.length})`}</h1>
      {loading ? (
        <strong>Loading...</strong>
      ) : (
        <select id="selectBox" onChange={onSelect}>
          <option>Select coin</option>
          {coins.map((coin) => (
            <option
              key={coin.id}
              id={coin.symbol}
              value={`'"dollar: ${coin.quotes.USD.price},${coin.symbol}'`}
            >
              {coin.name}({coin.symbol}): ${coin.quotes.USD.price.toFixed(8)}
            </option>
          ))}
        </select>
      )}
      <hr />
      {coinValue === "Select coin" ? null : (
        <div>
          <label htmlFor="dollar">If you have $</label>
          <input
            value={dollar}
            id="dollar"
            onChange={onChangeDollar}
            type="number"
            placeholder="type"
          />
          <h3>You can buy {dollar / coinValue} coins</h3>
        </div>
      )}
    </div>
  );
}

export default App;
